dtsPropsFor.Badge:
/** Halal-status / ownership tier the pill renders. */
type: "muis" | "admin" | "owned" | "friendly" | "nopork" | "pending" | "family" | "prayer";
/** Larger pill for headers / detail pages. */
lg?: boolean;

dtsPropsFor.StatCard:
label: string;
value: string | number;
/** Signed period-over-period change; null/undefined hides the delta badge (never a fake 0%). */
delta?: number | null;
deltaLabel?: string;
hint?: string;
/** Icon name from the shared Icon set (e.g. "store", "eye", "dollar"). */
icon?: string;

dtsPropsFor.ListingCard:
/** Directory business record. Reads id/slug, name, cuisine, area, rating, reviews, badges, blurb, image, open, distance, featured, franchise/outletCount, claimed. */
item: {
  id: string; slug?: string; name: string; cat?: string; cuisine: string; area: string;
  rating: number; reviews: number; badges: string[]; blurb: string;
  image?: string; img?: string; tone?: string; open: boolean; distance?: string;
  featured?: boolean; franchise?: boolean; outletCount?: number; claimed?: boolean;
  [key: string]: unknown;
};
variant?: "standard" | "featured" | "row";
/** Analytics hook fired when the card's main link opens. */
onOpen?: () => void;
